```csharp
using System;
using System.Linq;
using System.Linq.Expressions;

public abstract class BaseRepository<T> where T : class
{
    protected readonly DbContext _context;

    public BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual IQueryable<T> GetAll()
    {
        return _context.Set<T>();
    }

    public virtual IQueryable<T> GetByCondition(Expression<Func<T, bool>> condition)
    {
        return _context.Set<T>().Where(condition);
    }

    public virtual T GetById(object id)
    {
        return _context.Set<T>().Find(id);
    }

    public virtual T GetByDynamicField(string field, object value)
    {
        // Create a lambda expression based on the field and value
        var parameter = Expression.Parameter(typeof(T), "x");
        var memberExpression = Expression.PropertyOrField(parameter, field);
        var lambda = Expression.Lambda<Func<T, bool>>(
            Expression.Equal(memberExpression, Expression.Constant(value)),
            parameter);

        return _context.Set<T>().FirstOrDefault(lambda);
    }
}
